"""
MKT Original Commentary — Judges chapters 14–17
Run: python3 scripts/zc-original-judges-14-17.py

Ch14: Samson's marriage to the Timnite — riddle, lion, honey (20 verses)
Ch15: Jawbone of a donkey, En-hakkore spring (20 verses)
Ch16: Delilah, Nazirite vow breach, Dagon's temple (31 verses)
Ch17: Micah's shrine — household idols, private Levite priest (13 verses)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "14": {
    "1": "<p><em>wayyēreḏ šimšôn timnātāh wayyarʾ ʾiššāh bətimnātāh mibənôt pəlištîm</em> — 'Samson went down to Timnah and saw a woman in Timnah from the daughters of the Philistines.' <em>yāraḏ</em> (H3381, to go down) — Timnah (<em>timnātāh</em> H8553) lay in the Sorek Valley below the hill country of Dan, so 'going down' is geographically accurate. The woman is from the Philistines (<em>pəlištîm</em> H6430) — the dominant coastal people who oppressed Israel throughout Samson's era. Samson's entire career is conducted at the intersection of Israelite identity and Philistine territory; his marriages, riddles, and battles all occur on this borderland.</p>",
    "2": "<p><em>wayyaʿal wayyaggēḏ ləʾāḇîw ûləʾimmô wayyōʾmer ʾiššāh rāʾîtî lətimnātāh mibənôt pəlištîm wəʿattāh qəḥû-ʾōtāh lî ləʾiššāh</em> — 'He came up and told his father and his mother: I saw a woman in Timnah, from the daughters of the Philistines. Now get her for me as a wife.' <em>rāʾîtî</em> (H7200, I saw) — sight triggers desire throughout Samson's story: he sees the Timnite woman (14:1), the Gaza prostitute (16:1), and Delilah (16:4). The pattern of desire-from-sight leading to disaster mirrors the Eden narrative (Gen 3:6) and foreshadows his literal blindness in 16:21 — Samson who lived by sight ends without eyes. <em>qəḥû-ʾōtāh lî</em> (get her for me) — the imperative to parents; he makes demands rather than requests, a pattern of self-will throughout.</p>",
    "3": "<p><em>wayyōʾmer ləhî minnāh kî hîʾ yāšərāh bəʿênāy</em> — 'Get her for me, for she is right in my eyes.' <em>yāšar</em> (H3474, to be straight/right/upright) + <em>bəʿênāy</em> (in my eyes) — the same phrase as Judges' refrain '<em>hayyāšār bəʿênāyw</em>' (what is right in his own eyes, 17:6; 21:25). Samson's demand for this woman is the personal embodiment of the book's theological problem: Israel does what is right in its own eyes rather than in YHWH's eyes. His father objects on grounds of the ban against intermarriage (Deut 7:3); Samson overrides by asserting his own judgment. The narrator's aside in v4 — 'his father and mother did not know that it was from YHWH' — adds divine sovereignty: YHWH is working his purpose even through Samson's rebellious desire.</p>",
    "4": "<p><em>wəʾāḇîw wəʾimmô lōʾ yāḏəʿû kî mēYHWH hîʾ kî-ṯōʾănāh hûʾ məḇaqquēš miPəlištîm</em> — 'His father and mother did not know that it was from YHWH, for he was seeking an occasion against the Philistines.' <em>tōʾănāh</em> (H8385, occasion/pretext — from <em>ʾānaʾ</em>, to seek a pretext, only here) is the spark needed to start a conflict. YHWH is sovereignly using Samson's personal desires to create the necessary confrontation with Philistia. The verse is a remarkable statement of divine providence operating through human passions — YHWH does not approve of the intermarriage, yet works through it to accomplish his deliverance purpose.</p>",
    "5": "<p><em>wayyēreḏ šimšôn wəʾāḇîw wəʾimmô timnātāh wayyāḇōʾû ʾad-karmê timnāh wəhinnēh kəpîr ʾărāyôt šōʾēg liqrāʾtô</em> — 'Samson went down with his father and mother to Timnah; when he came to the vineyards of Timnah, behold, a young lion came roaring toward him.' <em>kəpîr ʾărāyôt</em> (H3715 H738, young lion — a lion past the cub stage, in full strength) — the Timnah vineyards are themselves ironic setting: Samson the Nazirite (<em>nāzîr</em>, consecrated to abstain from grapes, Num 6:4) walks through a vineyard on his way to compound his violations. The lion ambush sets up the honey riddle and triggers the Spirit's first public display through Samson.</p>",
    "6": "<p><em>wattiṣlaḥ ʿālāyw rûaḥ YHWH wayyəšassəʿēhû kəšassaʿ haggerî wəʾumāh ʾên bəyāḏô</em> — 'The Spirit of YHWH rushed upon him, and he tore it apart as one tears apart a young goat, and he had nothing in his hand.' <em>ṣālaḥ</em> (H6743, to rush/advance upon — used consistently for the Spirit's empowerment of the judges: 3:10 Othniel, 11:29 Jephthah, 14:19 Samson again; and 1 Sam 10:6,10; 16:13 for Saul and David) — the Spirit's arrival is sudden, powerful, and directive. <em>šissēaʿ</em> (H8156, to split/tear — the verb for tearing a young goat) applied to a lion: Samson tears a lion bare-handed. The 'nothing in his hand' detail is significant: this is pure Spirit-empowered strength, not a weapon feat.</p>",
    "7": "<p><em>wayyēreḏ wayyədabbēr lāʾiššāh wattiîšar bəʿênê šimšôn</em> — 'He went down and spoke with the woman, and she seemed right in Samson's eyes.' <em>wattiîšar</em> (H3474, she seemed right/good/pleasing) — the narrator repeats the root <em>yāšar</em> from v3: the woman who 'is right in my eyes' (v3) now 'seems right in his eyes' upon closer acquaintance. The repetition reinforces that Samson's evaluation is purely subjective and self-referential. He never learns her name; she exists in the narrative only in relation to him — a troubling pattern in the Samson cycle that reflects his inability to form covenantal relationships.</p>",
    "8": "<p><em>wayyelek ləqaḥtāh wayyāsar lirʾôt ʾēt mappelet hāʾaryēh wəhinnēh ʿăḏat dəḇôrîm bəgəwiyyat hāʾaryēh ûḏəḇāš</em> — 'He turned aside to see the carcass of the lion, and behold, there was a swarm of bees in the carcass of the lion, and honey.' <em>mappelet</em> (H4658, carcass/fallen thing — from <em>nāpal</em> to fall) — the lion's body. That bees have colonized it implies it has dried out (bees avoid rotting flesh). The honey in the lion's carcass is technically from a <em>ṭāmēʾ</em> (H2931, unclean) animal (Lev 11:27-28). Samson eats the honey without hesitation, compounding his Nazirite violations. The honey becomes his riddle's answer: sweet from the strong.</p>",
    "9": "<p><em>wayyirḏēhû ʾel-kappāyw wayyēlek hālôk wəʾākōl wayyēlek ʾel-ʾāḇîw wəʾel-ʾimmô wayyittēn lāhem wayyōʾkelû wəlōʾ higgîḏ lāhem kî mippegerhat hāʾaryēh rāḏāh hadəḇāš</em> — 'He scraped the honey into his hands and went on, eating as he went. He came to his father and mother and gave some to them, and they ate. But he did not tell them that he had scraped the honey from the carcass of the lion.' <em>rādāh</em> (H7287/H7300, to scrape/draw out — the specific act of extracting honey from a comb) — Samson knows that touching the lion's carcass renders him and anyone who touches his food ritually unclean (Num 6:6-9). He conceals this from his parents, making them unknowing participants in defilement. The concealment is not caution but complicity: the Nazirite violates his vow and involves his family.</p>",
    "10": "<p><em>wayyēreḏ ʾāḇîw ʾel-hāʾiššāh wayyaʿaś šam šimšôn mišteh kî kēn yaʿăśû habbaḥûrîm</em> — 'His father went down to the woman; Samson made a feast there, for so the young men used to do.' <em>mišteh</em> (H4960, feast/drinking feast — from <em>šātāh</em> H8354, to drink) — the feast was specifically a wine-drinking celebration, the standard wedding feast. That Samson the Nazirite makes a <em>mišteh</em> — a wine feast — is a direct Nazirite violation (Num 6:3: no wine or strong drink, no grape juice, no fresh or dried grapes). The narrator notes it was customary for young men, explaining why no one objects, but the violation stands: the consecrated man participates in what his vow forbids.</p>",
    "11": "<p><em>wayhî kirʾôtām ʾōtô wayyiqḥû šəlōšîm mēraʿîm wayyihyû ʾittô</em> — 'When they saw him, they brought thirty companions to be with him.' <em>mēraʿîm</em> (H4828 plural, companions/attendants) — the thirty companions assigned by the Philistines may have been social custom or security measure. In the context of Samson's isolation (his parents returned home) and the Philistine setting, thirty men watching him functions as surveillance. The number thirty becomes the wager amount: 30 linen garments and 30 festal garments (v12-13) — if Samson loses the riddle, these thirty men profit. If he wins, they must pay. Their subsequent extortion of the answer through his wife reveals their intent from the start.</p>",
    "12": "<p><em>wayyōʾmer lāhem šimšôn ʾāḥûḏāh-nāʾ lākem ḥîḏāh ʾim-hāḡēḏ taggîḏû ʾōtāh lî šiḇʿat yəmê hammišteh</em> — 'Samson said to them: Let me now put a riddle to you. If you can explain it to me within the seven days of the feast...' <em>ḥîḏāh</em> (H2420, riddle/enigma/dark saying — from <em>ḥûḏ</em> H2330, to tie knots) is a wisdom genre: a knotted saying that conceals meaning. Riddles were a form of wisdom contest at banquets (1 Kgs 10:1 — Queen of Sheba tested Solomon with <em>ḥîḏôt</em>). Samson's riddle is personal-autobiographical: only he and YHWH know the experience behind it, making it technically unsolvable from public knowledge.</p>",
    "13": "<p><em>wəʾim-lōʾ tûkəlû ləhaggîḏ lî wənatatttem ʾattem lî šəlōšîm sādîn wəšəlōšîm ḥălipôt bəḡāḏîm</em> — 'But if you cannot tell me, then you shall give me thirty linen garments and thirty changes of clothes.' <em>sādîn</em> (H5466, linen garment/sheet — fine linen undergarment) and <em>ḥălipôt bəḡāḏîm</em> (H2487 H899, changes of clothing — festal outer garments) — the wager involves two complete sets of clothing for thirty men each. The total value is substantial: 60 quality garments. Samson is wagering on the unprovability of a private experience; the Philistines are gambling that social pressure on his wife will extract the answer — which is exactly what they proceed to do.</p>",
    "14": "<p><em>min-hāʾōkēl yāṣāʾ maʾăkāl ûmēʿaz yāṣāʾ māṯôq</em> — 'Out of the eater came something to eat, and out of the strong came something sweet.' <em>ʾōkēl</em> (H398 participle, the eater — a lion) / <em>maʾăkāl</em> (H3978, food — honey) / <em>ʿaz</em> (H5794, strong/fierce — the lion) / <em>māṯôq</em> (H4966, sweet — honey). The riddle is a verbal paradox built on unexpected reversals: the destroyer produces food; the fierce produces sweetness. The answer requires knowing the specific lion-and-honey experience. Three days pass with no answer (v14b) — the riddle is genuinely impenetrable without inside knowledge.</p>",
    "15": "<p><em>wayhî bayyôm haššəḇîʿî wayyōʾmərû ləʾēšet šimšôn pittî ʾet-ʾîšēk wəyaggēḏ-lānû ʾet-haḥîḏāh</em> — 'On the seventh day they said to Samson's wife: Entice your husband, that he may tell us the riddle.' <em>pittāh</em> (H6601, to entice/seduce/deceive — the same verb used of false prophets in Ezek 14:9 and the seduction of a virgin in Exod 22:16) — the verb is strong: they are asking the woman to use seduction and manipulation to extract intelligence. <em>pen-niśrəpāh ʾôtāk wə-ʾet-bêt ʾāḇîk bāʾēš</em> — 'lest we burn you and your father's house with fire' — the threat is lethal and immediate; the woman is trapped between her husband and her people's threats.</p>",
    "16": "<p><em>wattibekkeh ʾēšet šimšôn ʿālāyw wattoʾmer śānēʾtanî wəlōʾ ʾăhaḇtānî</em> — 'Samson's wife wept over him and said: You only hate me; you do not love me.' <em>śānēʾ</em> (H8130, to hate — the antonym of covenant love <em>ʾāhab</em>) and <em>ʾāhab</em> (H157, to love) — the wife frames the riddle secret as a test of marital love. Her accusation reframes an intelligence extraction as an emotional appeal: if you loved me, you'd tell me. <em>haḥîḏāh ḥaḏtāh wəlōʾ higgadtāh lî</em> — 'you have put a riddle to my countrymen and have not told me.' The irony is that she is being coerced by her kinsmen to extract what she frames as a matter of love — her tears and accusations work on Samson's affections exactly as the Philistines calculated.</p>",
    "17": "<p><em>wattibekkeh ʿālāyw šiḇʿat hayyāmîm ʾăšer-hāyāh lāhem hammišteh wayhî bayyôm haššəḇîʿî wayyaggēḏ-lāh kî-hēṣîqat-lô</em> — 'She wept before him the seven days that their feast lasted, and on the seventh day he told her because she pressed him hard.' <em>hēṣîq</em> (H6693, to press hard/distress — same root as 16:16 where Delilah presses Samson daily until his soul was shortened to death) — the verb anticipates the Delilah pattern: a woman's persistent emotional pressure extracts Samson's secret. He is vulnerable to relational pressure from women in a way he is not vulnerable to physical force. The seven-day persistence is successful: love conquers the riddle's security.</p>",
    "18": "<p><em>wayyōʾmərû lô ʾanšê hāʿîr bayyôm haššəḇîʿî bəṭerem yiššaqep haḥammāh mah-māṯôq midəḇāš ûmah-ʿaz mēʾaryēh</em> — 'The men of the city said to him on the seventh day before the sun went down: What is sweeter than honey? What is stronger than a lion?' Samson's devastating response: <em>lûlēʾ ḥărašttem bəʿeglātî lōʾ məṣāʾtem ḥîḏātî</em> — 'If you had not plowed with my heifer, you would not have found out my riddle.' <em>ḥāraš</em> (H2790, to plow/engrave) + <em>ʿeglāh</em> (H5697, heifer) — the metaphor is agricultural and sexual: 'plowing with my heifer' = using my wife for your purposes. The image of a wife as a working animal is harsh and reflects Samson's objectifying perspective; yet it accurately captures what the Philistines did — they used her as a tool to extract information.</p>",
    "19": "<p><em>wattiṣlaḥ ʿālāyw rûaḥ YHWH wayyēreḏ ʾašqəlôn wayyak mēhem šəlōšîm ʾîš</em> — 'The Spirit of YHWH rushed upon him, and he went down to Ashkelon and struck thirty men of them.' The Spirit's empowerment here enables Samson's 'payment' of the wager debt — thirty sets of garments taken from thirty Philistine dead. This is the Spirit being used for what looks like personal vengeance, but the narrative frames it as YHWH's larger campaign against Philistia. Ashkelon (<em>ʾašqəlôn</em> H831) was one of the five major Philistine cities, demonstrating Samson's raids span the entire Philistine coastland.</p>",
    "20": "<p><em>wattihyeh ʾēšet šimšôn ləmērēʿēhû ʾăšer rēʿāh-lô</em> — 'And Samson's wife was given to his companion, who had been his best man.' <em>mērēʿ</em> (H4828, companion/friend — the companion who served as his best man at the wedding, called his <em>mērēʿ</em>) — the wife is transferred to the wedding companion when Samson abandons her in anger. This completes the Timnah episode's arc: Samson went down seeking a wife and returns without one. The transfer becomes the pretext for the fox-and-fire campaign (15:1-5). Every action in the Samson cycle sets up the next escalation; nothing is resolved cleanly because Samson acts from anger rather than covenant faithfulness.</p>"
  },
  "15": {
    "1": "<p><em>wayhî miyāmîm biqṣîr-ḥiṭṭîm wayyiqqōḏ šimšôn ʾet-ʾištô bigəḏî-ʿizzîm wayyōʾmer ʾābōʾāh ʾel-ʾištî haḥāḏərāh</em> — 'After some time, at the time of wheat harvest, Samson visited his wife with a young goat, and he said: I will go into my wife in the chamber.' The wheat harvest timing (<em>qəṣîr-ḥiṭṭîm</em>) places this return in late spring. <em>gəḏî-ʿizzîm</em> (H1423 H5795, young goat) — a young goat was a standard reconciliation/visit gift in ancient Near Eastern custom (Gen 38:17 Judah to Tamar; Gen 38:20). Samson returns expecting to resume the marriage, apparently unaware that his wife has been given away. The goat gift implies he is making a goodwill approach, not coming in anger — which makes the father's disclosure in v2 even more devastating.</p>",
    "2": "<p><em>wayyōʾmer ʾāḇîhā ʾāmōr ʾāmartî kî-śānōʾ śənēʾtāh</em> — 'But her father said: I really thought that you utterly hated her.' <em>śānōʾ śənēʾtāh</em> (infinitive absolute + finite verb — the intensified form: 'utterly hated') — the father explains his decision: Samson's angry departure after the wedding feast (14:19) was read as marital abandonment, and under ancient Near Eastern custom an abandoned wife could be given to another. <em>wāʾettənāh ləmērēʿăkā hălōʾ ʾăḥōtāh haqqəṭannāh ṭôḇāh mimmenāh</em> — 'so I gave her to your companion. Is not her younger sister more beautiful than she? Please take her instead.' The offer of the younger sister is a face-saving consolation prize; Samson's response rejects it and frames his response as righteous retaliation.</p>",
    "3": "<p><em>wayyōʾmer lāhem šimšôn niqqêtî happaʿam mippəlištîm kî-ʾōśeh ʾănî ʿimmāhem rāʿāh</em> — 'Samson said to them: This time I shall be blameless with regard to the Philistines, when I do them harm.' <em>niqqêtî</em> (H5352 Niphal, to be blameless/innocent/acquitted — from <em>nāqāh</em> H5352) — Samson declares his retaliatory action to be morally justified: he is making himself 'clean' or 'acquitted' by responding in kind. The logic is lex talionis (they wronged him; he is entitled to respond). Whether the declaration is theologically legitimate is ambiguous — YHWH does not comment. The narrative uses Samson's personal grievances as the vehicle for national-scale Philistine punishment, but Samson's framing is entirely self-referential.</p>",
    "4": "<p><em>wayyēlek šimšôn wayyilkoḏ šəlōš-mêʾôt šûʿālîm wayyiqqaḥ lappîḏîm wayyipeŋ zānāḇ ʾel-zānāḇ</em> — 'Samson went and caught three hundred foxes and took torches; he turned tail to tail and put one torch between each pair of tails.' <em>šûʿāl</em> (H7776, fox/jackal — both animals are intended by the word) — catching 300 animals is itself a Samson feat. <em>lappîḏ</em> (H3940, torch/firebrand — the same word as in Judg 7:16 where Gideon's men carry torches) — firebrands between paired fox tails would have created uncontrollable running fire through standing grain. The agricultural sabotage destroys the Philistine harvest at precisely the wrong moment — vindictive, effective, and proportionally catastrophic.</p>",
    "5": "<p><em>wayyabbeʿ-ʾēš balappîḏîm wayšallaḥ bəqāmôt pəlištîm wayyabʿar miggādîš wəʿaḏ-qāmāh wəʿaḏ-kerem zayit</em> — 'He lit the torches and set the foxes free into the standing grain of the Philistines, and burned up the shocks and the standing grain and also the olive orchards.' <em>gādîš</em> (H1430, shock of grain — grain already cut and stacked for drying) and <em>qāmāh</em> (H7054, standing grain — still unharvested) and <em>kerem zayit</em> (H3754 H2132, olive orchard) — three stages of agricultural production are destroyed: stored grain, unharvested grain, and the perennial orchards that take decades to mature. The olive trees are the most severe loss: destroying an olive grove sets back a community's food supply for a generation. This is total agricultural warfare.</p>",
    "6": "<p><em>wayyōʾmərû pəlištîm mî ʿāśāh zōʾt wayyōʾmərû šimšôn ḥătan hattimānî kî lāqaḥ ʾet-ʾištô wayyittnāh ləmērēʿēhû wayyaʿălû pəlištîm wayyiśrəpû ʾôtāh wəʾet-ʾāḇîhā bāʾēš</em> — 'The Philistines said: Who has done this? They said: Samson, the son-in-law of the Timnite, because he took his wife and gave her to his companion. And the Philistines came up and burned her and her father with fire.' The Philistines retaliate against the woman and her father for Samson's action — punishing the innocent parties rather than Samson himself. The burning of the woman (the very threat made in 14:15 to extract the riddle) comes full circle: the threat used to coerce her is now executed against her. The cycle of vengeance expands: Philistines burned Samson → Samson burned their fields → Philistines burned his wife → Samson strikes them again (v7-8).</p>",
    "7": "<p><em>wayyōʾmer lāhem šimšôn ʾim-tāʿăśûn kāzōʾt kî ʾim-niqqamtî bākem wəʾaḥar ʾeḥdāl</em> — 'Samson said to them: If you do this, I will surely take revenge on you, and after that I will stop.' <em>niqqam</em> (H5358, to avenge/take revenge — the same root as Samson's final prayer in 16:28) — Samson's life is structured as a cycle of revenge declarations followed by devastating acts of force. Each declaration escalates the conflict. The phrase <em>wəʾaḥar ʾeḥdāl</em> — 'and after that I will stop' — is Samson's pattern of self-imposed limits that he never actually keeps; the conflict always continues because his actions generate new retaliation.</p>",
    "8": "<p><em>wayyak ʾôtām šôq ʿal-yārēk makkāh gəḏôlāh wayyēreḏ wayyēšeḇ bəsəʿîp-sela haʿêṭām</em> — 'He struck them hip and thigh with a great blow, and he went down and stayed in the cleft of the rock of Etam.' <em>šôq ʿal-yārēk</em> (H7785 H3409, shin/thigh upon thigh — an idiom of uncertain origin, possibly from wrestling or battle, describing a thorough, total defeat: 'piling blow on blow') — 'hip and thigh' is a unique idiomatic expression meaning a comprehensive, unreserved slaughter. Samson then withdraws to the rock of Etam (<em>sela haʿêṭām</em>), a natural fortress in Judah's territory — the pattern of retreat after a major act of force that leaves the political problem unresolved.</p>",
    "9": "<p><em>wayyaʿălû pəlištîm wayyaḥănû bîhûḏāh wayyinnāṭəšû bəlaḥî</em> — 'Then the Philistines came up and encamped in Judah and made a raid on Lehi.' <em>nāṭaš</em> (H5203, to spread out/deploy/raid — used of armies spreading across terrain) — the Philistine incursion into Judah proper over a single man demonstrates both Samson's military significance to them and Judah's political vulnerability. <em>laḥî</em> (H3896, Lehi — meaning 'jawbone') is the place name that will receive its etiology from the upcoming battle (v9-17). The geographic specificity grounds the narrative: this is territory history, not legend.</p>",
    "10": "<p><em>wayyōʾmərû ʾanšê yəhûḏāh lāmāh ʿălîtem ʿālênû wayyōʾmərû laʾăsōr ʾet-šimšôn ʿālînû</em> — 'The men of Judah said: Why have you come up against us? They said: We have come up to bind Samson, to do to him as he did to us.' The Philistines' answer is specific: they want Samson, not territory. The men of Judah's compliance in v12-13 — binding their own deliverer to hand him to the enemy — is one of Judges' most disturbing moments: Israel has internalized subjugation so thoroughly that they participate in suppressing their own liberation. The oppressor controls them not just by force but by persuading them to police themselves.</p>",
    "11": "<p><em>wayyērdû šəlōšet ʾălāpîm ʾîš miyyəhûḏāh ʾel-səʿîp sela haʿêṭām wayyōʾmərû ləšimšôn hălōʾ yāḏaʿtā kî-mōšəlîm bānû pəlištîm</em> — 'Three thousand men of Judah went down to the cleft of the rock of Etam and said to Samson: Do you not know that the Philistines rule over us?' Three thousand men to arrest one man reflects either Samson's known strength or Judah's collective anxiety. <em>mōšəlîm</em> (H4910 Qal participle, ruling/having dominion) — the verb the Philistines 'rule over us' uses the same root as <em>mešel</em> (proverb/mashal) and governance; they rule as a settled political fact. Judah's question — 'do you not know?' — treats subjugation as normal common knowledge; Samson's disruption of the status quo is the problem, not the oppression itself.</p>",
    "12": "<p><em>wayyōʾmərû lô laʾăsōr-kā yāraḏnû lōsōr-kā ûlitttənkā bəyaḏ-pəlištîm wayyōʾmer lāhem šimšôn hišāḇəʿû lî pen-tipgəʿûn-bî ʾattem</em> — 'They said to him: We have come down to bind you, that we may give you into the hands of the Philistines. And Samson said to them: Swear to me that you will not attack me yourselves.' Samson's one condition — that his own people not strike him — reveals his trust calculus: he trusts Judah's oath more than the Philistines' restraint. <em>hišāḇəʿû</em> (H7650 Hiphil, to cause to swear) — Samson administers an oath to his own countrymen before surrendering to them. The scene is a grotesque inversion of military protocol: a deliverer being bound and surrendered by the people he came to deliver.</p>",
    "13": "<p><em>wayyōʾmərû lô lēʾmōr lōʾ ʾim-ʾāsōr neʾesārkā ûnətatnākā bəyāḏām wəhārōg lōʾ nahargekkā wayyaʾasrūhû bišənê ʿăbōtîm ḥăḏāšîm wayyaʿăluhû min-hassālaʿ</em> — 'They said to him: No; we will only bind you and give you into their hand. We will not kill you. So they bound him with two new ropes and brought him up from the rock.' <em>ʿăbōt ḥăḏāšîm</em> (H5688 H2319, new ropes) — the 'new ropes' detail anticipates ch16:11 where the same phrase appears in Delilah's second trap. The two new ropes that bind Samson here will dissolve like flax (v14) — the same pattern established in ch16 in reverse. Judah binds their deliverer with new ropes; the Spirit dissolves them. YHWH overrules Israel's complicity.</p>",
    "14": "<p><em>wattiṣlaḥ ʿālāyw rûaḥ YHWH wattihyênāh hāʾăḇôtîm ʾăšer ʿal-zərōʿāyw kappîštîm ʾăšer bāʿărû ḇāʾēš</em> — 'The Spirit of YHWH rushed upon him, and the ropes on his arms became like flax burned with fire.' For the third time in Samson's story <em>ṣālaḥ rûaḥ YHWH</em> — the Spirit rushes upon him. <em>pišṭāh</em> (H6593, flax/linen thread) + <em>bāʿar ḇāʾēš</em> (burning with fire) — the ropes that would bind him dissolve like burning flax. The metaphor captures instantaneous dissolution: fire makes flax structurally worthless immediately. This third Spirit-empowerment in ch14-15 establishes the pattern that will be broken in ch16.</p>",
    "15": "<p><em>wayyimṣāʾ lḥî-ḥāmôr ṭəriyyāh wayyišlaḥ yāḏô wayyiqqāḥēhû wayyak-bô ʾelep ʾîš</em> — 'He found a fresh jawbone of a donkey, reached out and took it, and struck down a thousand men with it.' <em>ləḥî-ḥāmôr</em> (H3895 H2543, jaw/cheek of a donkey) — the jawbone weapon is deliberately humble: not a sword, spear, or club but an agricultural animal's discarded bone. <em>ṭəriyyāh</em> (H2961, fresh/new — not yet dried and brittle) — the moisture in a fresh jawbone gives it structural integrity as a weapon. The contrast with conventional weapons echoes the theological principle of Judges: YHWH delivers through inadequate means (tent peg, jawbone) to make his exclusive agency clear.</p>",
    "16": "<p><em>wayyōʾmer šimšôn bilḥî haḥāmôr ḥămôr ḥămōrātayim bilḥî haḥāmôr hikkêtî ʾelep ʾîš</em> — 'Samson said: With the jawbone of a donkey, heaps upon heaps, with the jawbone of a donkey I have struck down a thousand men.' <em>bilḥî haḥāmôr</em> (with the jawbone of the donkey) — the victory song is a wordplay: <em>ḥāmôr</em> (H2543, donkey) sounds like <em>ḥōmer</em> (H2563, heap/pile of grain). <em>ḥămôr ḥămōrātayim</em> may be read as 'heaps, two heaps' — a doubling that intensifies the count. The boast song is Samson's only recorded speech-act of praise, and its grammar is military: first-person victorious declaration. Compare Deborah's song (ch5): Samson's victory song is self-referential where Deborah's is YHWH-referential.</p>",
    "17": "<p><em>wayhî kəkallōtô lədabbēr wayyašleḵ haləḥî miyyāḏô wayyiqrāʾ lamāqôm hahûʾ rāmat-laḥî</em> — 'When he had finished speaking, he threw away the jawbone, and that place was called Ramath-lehi.' <em>rāmat-laḥî</em> (H7437, 'height of the jawbone' or 'throwing of the jawbone') — the place name encodes the weapon's use. In Judges, place-naming is a consistent narrative practice marking sites of divine intervention: Beer-lahai-roi (Gen 16:14), Penuel (Gen 32:31), Bochim (Judg 2:5), and here. The physical jawbone becomes a geographic marker of YHWH's deliverance, preserved in the landscape as testimony.</p>",
    "18": "<p><em>wayyiṣmāʾ məʾōḏ wayyiqrāʾ ʾel-YHWH wayyōʾmer ʾattāh nātattā bəyaḏ-ʿaḇdəkā ʾet-hayyəšûʿāh hagdôlāh hazzōʾt</em> — 'He was very thirsty, and he called to YHWH and said: You have given this great salvation by the hand of your servant.' Samson prays — one of the rare moments of direct divine address in his story. <em>yəšûʿāh gəḏôlāh</em> (H3444 H1419, great deliverance/salvation) — covenant vocabulary for YHWH's saving acts. Even Samson must acknowledge that the victory was YHWH's gift. <em>waʾattāh ʾāmût baṣṣāmāʾ</em> — 'and now shall I die of thirst?' — after the great victory, ordinary thirst threatens the life YHWH just used for deliverance. The prayer is answered immediately (v19).</p>",
    "19": "<p><em>wayyibqaʿ ʾĕlōhîm ʾet-hammakteš ʾăšer ballĕḥî wayyēṣəʾû mimmennû mayim wayyišt wayyāšob rûḥô wayyiḥî</em> — 'God split open the hollow place that is in Lehi, and water came out from it, and he drank, and his spirit returned and he revived.' <em>bāqaʿ</em> (H1234, to split/break open — used of the Exodus sea, Ps 78:13; of the rock in the wilderness, Ps 78:15-16) — God provides water in the wilderness pattern. <em>makteš</em> (H4388, hollow/mortar — a bowl-shaped depression in rock) becomes the spring. The place is named <em>ʿên haqqôrēʾ</em> (H5879, 'Spring of the One Who Calls') — a place-name encoding Samson's prayer, preserved in geography as testimony to answered prayer.</p>",
    "20": "<p><em>wayyišpōṭ ʾet-yiśrāʾēl bîmê pəlištîm ʿeśrîm šānāh</em> — 'And he judged Israel in the days of the Philistines twenty years.' The twenty-year judgeship formula (<em>ʿeśrîm šānāh</em>) closes the Samson cycle's second act (cf. 16:31 where the same formula closes his career). The formula is deliberately minimal compared to other judges: no 'the land had rest for X years,' no summary of peace. The phrasing 'in the days of the Philistines' acknowledges that Samson's judgeship did not end Philistine domination — unlike Othniel, Deborah, or Gideon, Samson did not liberate the land. He harassed the Philistines without resolving the crisis, leaving the work for Samuel and David.</p>"
  },
  "16": {
    "1": "<p><em>wayyēlek šimšôn ʿazzātāh wayyarʾ-šam ʾiššāh zônāh wayyāḇôʾ ʾēlêhā</em> — 'Samson went to Gaza and saw there a prostitute, and he went in to her.' The Samson cycle's third woman follows the pattern: Samson sees (<em>rāʾāh</em>) and goes in. Gaza (<em>ʿazzāh</em> H5804) was one of the five Philistine capital cities — the deepest Samson has gone into enemy territory. <em>zônāh</em> (H2181, prostitute — from <em>zānāh</em>, to commit fornication/whoredom; the same root used metaphorically for Israel's spiritual adultery throughout Judges) — Samson the Nazirite in a Philistine city with a prostitute is the nadir of his Nazirite faithfulness before ch16's climax.</p>",
    "2": "<p><em>laʿazzātîm lēʾmōr bāʾ šimšôn hēnnāh wayyāsōbbû wayyeʾerəbû-lô kol-hallayla bəšaʿar hāʿîr</em> — 'The Gazites were told: Samson has come here. And they surrounded the place and waited all night at the gate of the city. They kept quiet all night, saying: Let us wait till the light of morning; then we will kill him.' <em>wayyeʾerəbû</em> (H693, to lie in wait/ambush) — Gaza sets an ambush, keeping quiet through the night. The gate of the city (<em>šaʿar hāʿîr</em>) was the city's strongest defensive feature, controlling entrance and exit. The Gazites' patience and planning — waiting till morning light — contrasts with Samson's casual night visit; they are hunters setting a trap.</p>",
    "3": "<p><em>wayyiškaḇ šimšôn ʿad-ḥăṣôt hallaylāh wayyāqom baḥăṣôt hallaylāh wayyeʾĕḥōz bedaltôt šaʿar-hāʿîr ûbišnê hammezûzôt wayyisśāʾēm ʿim-habərîaḥ wayyāśem ʿal-kətēpāyw wayyaʿălēm ʾel-rōʾš hāhār ʾăšer ʿal-pənê ḥeḇrôn</em> — 'Samson lay until midnight, and at midnight he arose and took hold of the doors of the gate of the city and the two posts, and pulled them up, bar and all, and put them on his shoulders and carried them to the top of the hill that is in front of Hebron.' The midnight escape with the city gate is Samson at his most audacious: a city gate with its posts and bar weighed several tons. <em>ḥeḇrôn</em> (H2275, Hebron) is approximately 40 miles from Gaza and sits on a high ridge — the carrying of Gaza's gate to Hebron's hill is a symbolic emasculation of Philistine power: their city's greatest defensive barrier removed and deposited in Israelite territory.</p>",
    "4": "<p><em>wayyelek wayyeʾĕhab ʾiššāh binḥal śôrēq ûšəmāh dəlîlāh</em> — 'He went and loved a woman in the Valley of Sorek whose name was Delilah.' <em>ʾāhab</em> (H157, to love — used of covenant/romantic love; cf. Deut 6:5 loving YHWH) — Samson 'loved' Delilah with the same verb as covenant-love; the tragic irony is that she will betray this love for money. <em>dəlîlāh</em> (H1807) — her name may derive from <em>dālal</em> (H1809, to dangle/hang low, to be brought low) or from <em>dālāh</em> (to draw water). The Sorek Valley (<em>naḥal śôrēq</em> H8256) runs from the Judean hills to the Mediterranean — deep in borderland territory between Israel and Philistia.</p>",
    "5": "<p><em>wayyaʿălû ʾēlêhā sarnê pəlištîm wayyōʾmərû lāh pittî ʾôtô ûrəʾî bammāh kōḥô gāḏôl ûbammāh nûkal lô waʾăsarnûhû ləʿannōtô wəʾănaḥnû nittēn-lāk ʾîš ʾelep ûmēʾāh kāsep</em> — 'The lords of the Philistines came up to her and said to her: Entice him, and see where his great strength lies, and by what means we may overpower him, that we may bind him to humble him. And we will each give you 1100 pieces of silver.' <em>sarnê pəlištîm</em> (H5633, lords of the Philistines — the five <em>sərānîm</em>, one from each city: Gaza, Ashkelon, Ashdod, Gath, Ekron) — all five lords are involved; this is a national-level operation. 1100 × 5 = 5,500 pieces of silver is an enormous sum. <em>pittî</em> (H6601, entice/seduce) — the same verb used of enticing Samson's wife in 14:15. The Philistines know what worked once.</p>",
    "6": "<p><em>wattoʾmer dəlîlāh ʾel-šimšôn haggîḏāh-nāʾ lî bammāh kōḥăkā gāḏôl</em> — 'Delilah said to Samson: Please tell me where your great strength lies.' <em>kōaḥ</em> (H3581, strength/power/force) is the key word of ch16 — it appears in Delilah's question (v6), her repeated interrogation (vv9,15), and in Samson's final prayer ('strengthen me just this once,' v28). The ultimate source of Samson's strength is not physical but spiritual — the Nazirite consecration that made him YHWH's separated person. Samson initially lies (vv7,11,13) — he knows the truth is spiritually dangerous, but the relationship pressure gradually erodes his resistance.</p>",
    "7": "<p><em>wayyōʾmer ʾēlêhā šimšôn ʾim-yāsərûnî bəšiḇʿāh yətārôt laḥôt ʾăšer lōʾ-yāḇəšû wəḥālîtî wəhāyîtî kəʾaḥaḏ hāʾāḏām</em> — 'Samson said to her: If they bind me with seven fresh bowstrings that have not been dried, I shall become weak and be like any other man.' <em>yetār laḥ</em> (H3499 H3892, fresh bowstring/sinew — from a freshly slaughtered animal, still moist) — fresh sinew retains its elasticity; it was used for bow strings when still moist. The 'seven' (<em>šiḇʿāh</em>) is the number of completeness. Samson's first deception locates his power in material: physical binding. This misdirection will be repeated twice more, each time moving closer to the real answer — the hair and the consecration it represents.</p>",
    "8": "<p><em>wayyaʿălû-lāh sarnê pəlištîm šiḇʿāh yətārôt laḥôt ʾăšer lōʾ-yāḇəšû wattaʾasrēhû bāhem</em> — 'The lords of the Philistines brought up to her seven fresh bowstrings that had not been dried, and she bound him with them.' Delilah actively binds Samson — in their own bed, evidently, since the ambushers are 'in the inner room' (v9). The extraordinary intimacy of the trap: Samson allows himself to be bound by someone he loves, in a private domestic setting, with enemies waiting in the next room. His trust is so complete that he does not perceive the danger even though the scenario should be obvious. The Philistine lords fund the operation and supply materials but Delilah does the actual binding.</p>",
    "9": "<p><em>wəhāʾōrēb yōšēḇ lāh bāḥāḏer wattoʾmer ʾēlāyw pəlištîm ʿālêkā šimšôn wayyənatteq ʾet-hayyətārôt kaʾăšer yinnātēq pətîl-hanuʿōret bəharîḥô ʾēš</em> — 'The ambushers were sitting in her inner room; she said to him: The Philistines are upon you, Samson! But he snapped the bowstrings, as a thread of tow snaps when it touches the fire.' <em>hāʾōrēb</em> (H693, ambushers/liers in wait) — the domestic ambush is a perversion of the marriage bed: the bedroom becomes a trap. Samson's destruction of the bowstrings is instant and effortless, like burning thread. <em>pətîl-hanuʿōret</em> (H6306, a thread/cord of tow — the coarse, easily ignited fiber of flax) is the simile for how quickly the bowstrings dissolved. The deception is exposed but Samson does not flee or break off the relationship.</p>",
    "10": "<p><em>wattoʾmer dəlîlāh ʾel-šimšôn hinnēh hēteltatnî watədabbēr ʾēlay kəzāḇîm</em> — 'Delilah said to Samson: Behold, you have mocked me and told me lies. Please tell me by what means you might be bound.' <em>hētel</em> (H2048, to mock/deceive — from <em>tālaʿ</em>, to deceive; rare term) — Delilah accuses Samson of lying to her, framing her surveillance as a matter of relational integrity. The accusation is audacious: she who is gathering intelligence for his enemies accuses him of dishonesty. Yet Samson accepts the framing and answers again. His willingness to continue engaging with the question — even after the ambush attempted to kill him — reveals his fatal attachment to Delilah despite all evidence.</p>",
    "11": "<p><em>wayyōʾmer ʾēlêhā ʾim-ʾāsōr yaʾasrûnî baʿăḇōtîm ḥăḏāšîm ʾăšer lōʾ-naʿăśāh bāhem məlāʾkāh wəḥālîtî wəhāyîtî kəʾaḥaḏ hāʾāḏām</em> — 'He said to her: If they bind me with new ropes that have not been used, I shall become weak and be like any other man.' <em>ʿăḇōtîm ḥăḏāšîm</em> (H5688 H2319, new ropes) — the same ropes that bound Samson in 15:13 and were dissolved by the Spirit. The second deception moves from organic material (sinew) to manufactured rope — Samson is moving the answer systematically away from the truth (his hair/vow) by offering plausible-sounding alternatives. Yet each failure should teach Delilah something, and it does: the ropes are as ineffective as the bowstrings.</p>",
    "12": "<p><em>wattaʾasrēhû dəlîlāh baʿăḇōtîm ḥăḏāšîm wattōʾmer ʾēlāyw pəlištîm ʿālêkā šimšôn wəhāʾōrēb yōšēḇ bāḥāḏer wayyənatqēm mēʿal zərōʿōṯāyw kaḥûṭ</em> — 'Delilah bound him with new ropes and said to him: The Philistines are upon you, Samson! And the ambushers were sitting in the inner room. But he snapped them off his arms like a thread.' The ropes snap 'like a thread' (<em>kaḥûṭ</em> H2339) — even finer than the previous simile. The escalating ease of escape signals that the problem is not the type of binding material but the source of Samson's power. Each failed attempt is narrowing the investigative space toward the real answer: his consecration, not his muscles.</p>",
    "13": "<p><em>wattoʾmer dəlîlāh ʾel-šimšôn ʿad-hēnnāh hētaltatnî wattədabbēr ʾēlay kəzāḇîm haggîḏāh-llî bammāh tuʾāsar</em> — 'Delilah said to Samson: Until now you have mocked me and told me lies. Tell me by what you might be bound.' The third accusation of lying uses the same formula as the second (v10): <em>hētel</em> + <em>kəzāḇîm</em>. The repetition of the accusation structure reveals Delilah's methodology: emotional pressure, accusation of dishonesty, renewed request. Each cycle of accusation is slightly more intense. Samson is trapped between knowing he shouldn't answer and being unable to withstand the relational pressure she applies.</p>",
    "14": "<p><em>wattitqaʿ bayyātēd wattōʾmer ʾēlāyw pəlištîm ʿālêkā šimšôn wayyîqaṣ miššənātô wayyissaʿ ʾet-hayyātēḏ ʾet-haʾāreg wəʾet-hamannôr</em> — 'She pinned it with the pin and said to him: Philistines are upon you, Samson! But he awoke from his sleep and pulled away the pin, the loom, and the web.' The third deception involves weaving Samson's hair into a loom's fabric — Delilah has moved to the hair itself, recognizing from Samson's evasions that the hair is involved. <em>yātēḏ</em> (H3489, pin/peg — the weaving pin) — she pins the woven web containing his hair to the loom. He tears it all away while asleep — yet still does not understand or refuse to return. The hair has been touched and he felt nothing: the Nazirite vow is more about consecration than the physical hair alone.</p>",
    "15": "<p><em>wattoʾmer ʾēlāyw ʾêk tōʾmar ʾăhaḇtîkā wəlibbəkā ʾên ʾittî</em> — 'She said to him: How can you say: I love you, when your heart is not with me?' <em>ʾāhaḇtîkā</em> (H157, I love you) — Delilah weaponizes Samson's love declaration: if you love me, you'll tell me. <em>wəlibbəkā ʾên ʾittî</em> — 'your heart is not with me' — the accusation reaches deeper than dishonesty; she claims he is withholding himself, keeping a secret that proves the love is partial. The accusation resonates because it contains a truth: there is something Samson has not told her. Her reading is correct even though her purpose is predatory.</p>",
    "16": "<p><em>wayhî kî-hēṣîqāh-lô biddəḇārêhā kol-hayyāmîm wattəʾallāṣēhû wayyiqṣar napšô lamût</em> — 'When she pressed him hard with her words day after day, and urged him, his soul was shortened to the point of death.' <em>hēṣîq</em> (H6693, to press hard/distress — identical verb as 14:17 where Samson's wife pressed him during the seven-day feast) — the pattern is deliberate: Samson's first wife pressed him for seven days to extract the riddle; Delilah presses him daily until his soul collapses. <em>wayyiqṣar napšô lamût</em> (his soul/life was shortened to death) — <em>qāṣar nepeš</em> is a Hebrew idiom for reaching the breaking point of endurance (cf. Num 21:4; Zech 11:8). Samson's will collapses not under physical threat but under relentless relational attrition.</p>",
    "17": "<p><em>wayyaggēḏ-lāh ʾet-kol-libbô wayyōʾmer lāh môrāh lōʾ-ʿālāh ʿal-rōʾšî kî-nəzîr ʾĕlōhîm ʾānî mibbeṭen ʾimmî</em> — 'He told her all his heart and said to her: A razor has never come upon my head, for I have been a Nazirite to God from my mother's womb.' <em>kol-libbô</em> (H3820, all his heart) — full disclosure. <em>môrāh</em> (H4177, razor) — the razor that has never touched his head. <em>nəzîr ʾĕlōhîm</em> (H5139, Nazirite of God) — the Nazirite vow (Num 6:1-21) involved three separations: no grape products, no razor, no contact with corpses. Samson has violated the first and third throughout his story; the hair alone remains. The disclosure is suicide by confession.</p>",
    "18": "<p><em>wattirrəʾ dəlîlāh kî-higgîḏ lāh ʾet-kol-libbô wattiššlaḥ wattiqrāʾ lisarnê pəlištîm lēʾmōr ʿălû happaʿam hazzeh kî higgîḏ lî ʾet-kol-libbô</em> — 'When Delilah saw that he had told her all his heart, she sent and called the lords of the Philistines, saying: Come up once more, for he has told me all his heart.' <em>wattirrəʾ</em> (H7200, and she saw) — Delilah perceives the truth of the disclosure: she recognizes sincerity where the previous three answers were evasions. How? The previous answers were testable and failed the test; this answer she verifies differently — perhaps through Samson's emotional vulnerability, perhaps through the specificity of 'from my mother's womb.' The Philistine lords come immediately, bringing the 1100 silver (v18b).</p>",
    "19": "<p><em>wattiśan ʾet-šiḇʿat maḥlĕpôt rōʾšô wayttəḥel ləʿannôṯô</em> — 'She shaved off the seven locks of his head.' <em>maḥlāpôt</em> (H4253, locks/braids of hair — from <em>ḥālap</em> H2498, to pass through/change) — the seven locks correspond to seven units of consecrated growth. <em>ʿinnāh</em> (H6031, to afflict/humble/weaken) — with the shaving she 'humbles/afflicts' him; his strength departs. The verb <em>ʿinnāh</em> is also the word for the affliction of the oppressed — Samson now becomes the afflicted rather than the deliverer.</p>",
    "20": "<p><em>wəhûʾ lōʾ yāḏaʿ kî YHWH sār mēʿālāyw</em> — 'But he did not know that YHWH had turned away from him.' The most tragic statement in the Samson narrative. <em>sār</em> (H5493 <em>sûr</em>, to turn aside/depart) — YHWH's presence-departure is the reversal of the commissioning promises ('YHWH is with you'). The fact that Samson 'does not know' (H3045 <em>yāḏaʿ</em>) is the spiritual tragedy: he still expects his strength to function as before (v20b — 'I will go out as before and shake myself free'). The assumption that YHWH's enabling presence continues even after covenant violation is the theological danger Samson embodies — presuming on grace while abandoning its conditions.</p>",
    "21": "<p><em>wayyōʾḥăzûhû pəlištîm wayyənaqərû ʾet-ʿênāyw wayyôrîḏûhû ʿazzātāh wayyaʾasrûhû bənḥušताyim wayhî ṭôḥên baḇêt hāʾăsûrîm</em> — 'And the Philistines seized him and gouged out his eyes and brought him down to Gaza and bound him with bronze shackles. And he ground at the mill in the prison.' <em>nāqar ʿênayim</em> (H5365 H5869, to gouge out eyes) — blinding captured enemies was standard ANE practice to prevent escape and further resistance (cf. 2 Kgs 25:7, Zedekiah blinded). The irony is complete: Samson who saw and desired women (14:1; 16:1,4) loses the very faculty that drove him. <em>ṭāḥan</em> (H2912, to grind — mill work was done by women and slaves, Exod 11:5; Isa 47:2) — Samson the mighty judge is reduced to slave labor at a hand-mill, the most humiliating work possible.</p>",
    "22": "<p><em>wayyāḥel śəʿar-rōʾšô litzammēaḥ kaʾăšer gullāḥ</em> — 'But the hair of his head began to grow again after it had been shaved.' The regrowth of Samson's hair is quiet, undramatic, and not commented on until this verse — signaling that YHWH's plan has not ended. <em>gālaḥ</em> (H1548, to shave — the same verb used in v19) / <em>ṣāmaḥ</em> (H6779, to grow/sprout) — the sprouting is the same verb used for vegetation growth, new shoots. The new hair represents new consecration: not the old Nazirite vow (which cannot be restored once broken, Num 6:12) but YHWH's sovereign re-empowerment for the final act.</p>",
    "23": "<p><em>wəsarnê pəlištîm neʾespû lizbaḥ zebaḥ-gāḏôl lədāgôn ʾĕlōhêhem ûləśimḥāh wayyōʾmərû nātan ʾĕlōhênû bəyāḏênû ʾet-šimšôn ʾôyəḇênû</em> — 'The lords of the Philistines gathered to offer a great sacrifice to Dagon their god and to rejoice. They said: Our god has given Samson our enemy into our hand.' <em>Dāgôn</em> (H1712) — the principal deity of the Philistines, cognate with <em>dāgān</em> (H1715, grain/cereal) or possibly with Ugaritic <em>dgn</em>. <em>nātan ʾĕlōhênû</em> — 'our god has given' — the Philistines credit their deity for what YHWH accomplished through Samson's covenant violation. The theological irony is layered: it was Samson's abandonment of YHWH's covenant that enabled his capture; the Philistines read YHWH's withdrawal as Dagon's victory.</p>",
    "24": "<p><em>wayyirʾû ʾōtô hāʿām wayyəhalləlû ʾet-ʾĕlōhêhem kî ʾāmərû nātan ʾĕlōhênû bəyāḏênû ʾet-ʾôyəḇênû</em> — 'When the people saw him, they praised their god. For they said: Our god has given our enemy into our hand.' The public celebration of Samson's capture is a national religious event for Philistia: the praise (<em>hillēl</em> H1984, to praise — from which <em>hallēlûyāh</em>) directed to Dagon is the Philistine counter-liturgy to Israel's praise of YHWH. The narrative sets up the dramatic reversal: the very celebration that mocks YHWH will become the occasion for YHWH's final vindication through Samson.</p>",
    "25": "<p><em>wayhî kîṭôḇ libbām wayyōʾmərû qirəʾû ləšimšôn wîśaḥeq-lānû wayyiqrəʾû ləšimšôn mibbêt hāʾăsûrîm wayyəṣaḥeq lipnêhem</em> — 'When their hearts were merry, they said: Call Samson, that he may entertain us. So they called Samson out of the prison, and he entertained them. They made him stand between the pillars.' <em>śāḥaq</em> (H7832, to play/make sport — but also to mock/laugh at; cf. Gen 21:9 Ishmael 'playing' which got him expelled) — Samson is brought out as entertainment, a spectacle for Philistine amusement. The position between the pillars (<em>bên hāʿammûḏîm</em>) is the strategic position from which Samson will pull the temple down. What the Philistines arrange as public humiliation, YHWH arranges as the setup for the final act.</p>",
    "26": "<p><em>wayyōʾmer šimšôn ʾel-hannáʿar hammahăzîq bəyāḏô hanîḥāh-ʾôtî wəhāmišēnî ʾet-hāʿammûḏîm ʾăšer habbayyit nākôn ʿălêhem wəʾeššāʿēn ʿălêhem</em> — 'Samson said to the young man who held him by the hand: Let me feel the pillars on which the house rests, that I may lean against them.' The blind Samson must be led by a young attendant — his dependence is total. <em>māšaš</em> (H4184, to feel/touch — the touch of a blind person groping) — the request to 'feel the pillars' is framed as needing support; his actual purpose is to find the structural load-bearing columns. The young attendant brings him to exactly the right place.</p>",
    "27": "<p><em>wəhayyit māle haʾanāšîm wəhannāšîm wəšām kol-sarnê pəlištîm wəʿal-hagagg kišəlōšet ʾălāpîm ʾîš wəʾiššāh hārōʾîm bəśeḥôq šimšôn</em> — 'Now the house was full of men and women. All the lords of the Philistines were there, and on the roof there were about three thousand men and women, who looked on while Samson entertained.' The crowd count establishes the scale of the catastrophe: approximately 3,000 on the roof, plus the floor level — the total death toll in v30 ('those he killed at his death were more than those he killed in his life') is enabled by this massive gathering. All five Philistine lords are present (v27) — the decapitation of the Philistine leadership structure is total.</p>",
    "28": "<p><em>wayyiqrāʾ šimšôn ʾel-YHWH wayyōʾmer ʾăḏōnāy YHWH zākərēnî nāʾ wəḥazzəqēnî nāʾ ʾaḵ happaʿam hazzeh hāʾĕlōhîm wəʾiqqāməh niqmat-ʾaḥat miššətê ʿênāy mippəlištîm</em> — 'Samson called to YHWH and said: Lord YHWH, remember me please, and please strengthen me just this once, O God, that I may be avenged on the Philistines for one of my two eyes.' <em>zākar</em> (H2142, remember) — the covenant memory-language: YHWH remembering is his acting on prior commitment (cf. Gen 8:1; Exod 2:24). <em>ḥāzaq</em> (H2388, to strengthen) — the prayer is for restored strength. <em>nāqam</em> (H5358, to avenge) — Samson's prayer frames the final act as personal revenge rather than covenant deliverance; yet he killed more in his death than in his life.</p>",
    "29": "<p><em>wayyilpōt šimšôn ʾet-šənê ʿammûḏê haṯṯāwek ʾăšer habbayyit nākôn ʿălêhem wayyissāʿēn ʿălêhem</em> — 'Samson grasped the two middle pillars on which the house rested, and he leaned his weight against them, his right hand on the one and his left hand on the other.' <em>ʿammûḏê haṯṯāwek</em> (H5982 H8432, the middle pillars — the central load-bearing columns of the temple structure) — Philistine temples of this period are archaeologically attested with two central pillars supporting the roof (cf. the temple excavated at Tell Qasile). Samson embraces both pillars simultaneously — a final act requiring the arm-span strength that defined his whole career. <em>wayyissāʿēn ʿălêhem</em> (he leaned upon them) — the posture before the push.</p>",
    "30": "<p><em>wayyōʾmer šimšôn tāmôt napšî ʿim-pəlištîm wayyēṭ bəkōaḥ</em> — 'Samson said: Let me die with the Philistines! And he bowed with all his might.' <em>napšî</em> (H5315, my soul/life/self) — his self-dedication to death. <em>kōaḥ</em> (H3581, might/strength) — the word that dominated the chapter returns for its final use. The temple of Dagon (<em>hêkal dāgôn</em>, H1712) collapses — Dagon the grain deity's house destroyed while 3,000 worshipers celebrate victory over YHWH's champion is an implicit defeat of the deity itself. <em>raḇ hammetîm ʾăšer-hēmît bəmôtô miʾăšer hēmît bəḥayyāyw</em> — 'the dead whom he killed at his death were more than those he had killed during his life' — the tragic calculus of a flawed champion's greatest victory.</p>",
    "31": "<p><em>wayyērəḏû ʾeḥāyw wəkol-bêt ʾāḇîw wayyiśśəʾû ʾōtô wayyaʿălû wayyiqbərû ʾôtô bên-ṣorʿāh ûḇên-ʾeštāʾōl bəqeḇer mānôaḥ ʾāḇîw wəhûʾ šāpaṭ ʾet-yiśrāʾēl ʿeśrîm šānāh</em> — 'Then his brothers and all his father's house came down and took him and brought him up and buried him between Zorah and Eshtaol in the tomb of Manoah his father. He had judged Israel twenty years.' Samson is buried in his ancestral ground, between Zorah and Eshtaol where the Spirit first stirred him (13:25). The family comes — his family, not Israel's tribes. No national mourning, no statement that 'the land had rest' — only the repeated twenty-year formula. Samson's epitaph is a judge who judged and died, personally significant but never nationally transformative. The Spirit that first stirred at Zorah-Eshtaol is the Spirit that ended at Gaza.</p>"
  },
  "17": {
    "1": "<p><em>wayhî-ʾîš mêhar ʾeprayim ûšəmô mîkāyəhû</em> — 'There was a man of the hill country of Ephraim whose name was Micayahu.' <em>mîkāyəhû</em> (H4318, Micayahu — 'who is like YHWH?') — the name is a rhetorical question praising YHWH's incomparability (cf. Exod 15:11: <em>mî-kāmōkā bāʾēlim YHWH</em>). The irony is thick: a man whose name asks 'who is like YHWH?' will fill his house with idols. The hill country of Ephraim was Israelite heartland territory, not a borderland — this corruption is not a peripheral problem but central to Israel's society.</p>",
    "2": "<p><em>wayyōʾmer ʾel-ʾimmô ʾelep ûmēʾāh hakkāsep ʾăšer luqqaḥ-lāk wattəʾallî wəgam ʾāmart bəʾāznāy hinnēh hakkesef ʾittî ʾănî laqāḥtîw</em> — 'He said to his mother: The 1100 pieces of silver that were taken from you, about which you uttered a curse in my hearing — behold, the silver is with me; I took it.' <em>ʾālāh</em> (H422, to curse/swear/bind with an oath) — the mother had invoked a curse on the thief; Micah confesses to avoid the curse's effect. <em>kāsep</em> (H3701, silver) — 1100 pieces of silver is exactly the amount each Philistine lord paid Delilah (16:5), creating a literary echo: the narrative moves from Samson's destruction by silver to Micah's corruption by silver.</p>",
    "3": "<p><em>wayyāšeb ʾet-ʾelep ûmēʾāh hakkāsep ləʾimmô wattoʾmer ʾimmô haqḏēš hiqdaštî ʾet-hakkesef laYHWH miyyāḏî liḇnî laʿăśôt pāsael ûmassēkāh</em> — 'He returned the 1100 pieces of silver to his mother, and his mother said: I truly dedicate the silver to YHWH from my hand for my son, to make a carved image and a molten image.' <em>hiqḏîš</em> (H6942, to consecrate/set apart as holy) — dedicating money to YHWH, then immediately directing it toward idol manufacture, is the chapter's central theological contradiction. <em>pāsal</em> (H6459, carved/graven image) and <em>massēkāh</em> (H4541, cast/molten image) — both types of idol are prohibited by the second commandment (Exod 20:4; Deut 5:8). The mother uses YHWH's name to consecrate what YHWH forbids.</p>",
    "4": "<p><em>wayyāšeb ʾet-hakkesef ləʾimmô wayyiqqaḥ ʾimmô mēʾātayim kāsep wattitnēhû laṣṣôrep wayyaʿaśēhû pāsal ûmassēkāh wayhî bəbêt mîkāyəhû</em> — 'He returned the silver to his mother, and his mother took 200 pieces of silver and gave them to the silversmith, who made them into a carved image and a molten image. And it was in the house of Micah.' <em>ṣôrep</em> (H6884, silversmith/refiner — from <em>ṣārap</em>, to refine metal, test by fire) — the professional craftsman executes the commission. Only 200 of the 1100 pieces go toward the idol; the rest remains with the mother. The idols are installed in the domestic space: <em>bêt mîkāyəhû</em> (the house of Micah) — the household shrine begins with professional-grade idols, immediately setting up the escalation in v5.</p>",
    "5": "<p><em>wəhāʾîš mîkāh lô bêt ʾĕlōhîm wayyaʿaś ʾêpôḏ ûtərāpîm wayyəmallēʾ ʾet-yaḏ ʾaḥaḏ mibānāyw wayyəhî-lô ləkōhēn</em> — 'And the man Micah had a house of gods; he made an ephod and household gods, and he installed one of his sons who became his priest.' <em>bêt ʾĕlōhîm</em> (house of God/gods — same phrase as Bethel, Gen 28:17) — a private shrine mimicking the tabernacle. <em>ʾêpôḏ</em> (H646, ephod — the priestly garment of the high priest, Exod 28:4-14; cf. Gideon's ephod in 8:27 which 'became a snare'). <em>tərāpîm</em> (H8655, household gods — the objects Rachel stole from Laban, Gen 31:19; used for divination, 1 Sam 15:23). <em>millēʾ yāḏ</em> (H4390 H3027, to fill the hand — the ordination idiom, Exod 28:41) — Micah installs his son as priest, violating the Levitical monopoly (Num 3:5-10).</p>",
    "6": "<p><em>bayyāmîm hāhēm ʾên meleḵ bəyiśrāʾēl ʾîš hayyāšār bəʿênāyw yaʿăśeh</em> — 'In those days there was no king in Israel. Everyone did what was right in his own eyes.' The refrain appears here for the first time in its full form (cf. 18:1; 19:1; 21:25). <em>meleḵ</em> (H4428, king) — the absence of kingship is the structural diagnosis: without a human king, there is no covenant enforcement. <em>hayyāšār bəʿênāyw</em> (what is right in his own eyes) — each person substitutes personal moral judgment for covenant law. This is a reversal of the Shema: Israel should do what is right in YHWH's eyes (Deut 12:8,25,28; 13:18) — the formula here substitutes <em>ʿênāyw</em> (his eyes) for <em>ʿênê YHWH</em> (the eyes of YHWH).</p>",
    "7": "<p><em>wayhî-naʿar mibbêt leḥem yəhûḏāh mimmišpaḥat yəhûḏāh wəhûʾ lēwî wəhûʾ gār-šam</em> — 'Now there was a young man from Bethlehem in Judah, from the clan of Judah. He was a Levite, and he was sojourning there.' <em>lēwî</em> (H3878, Levite) — the Levites had no tribal territorial allotment; they were to be distributed among Israel's cities with their own towns and pasture lands (Josh 21). A Levite from Bethlehem who is 'sojourning there' — in his own tribe's territory — suggests this Levite is displaced or rootless, not settled in his designated Levitical city. This instability makes him available for hire, setting up the private chaplaincy arrangement.</p>",
    "8": "<p><em>wayyēlek hāʾîš mēhāʿîr mibbêt leḥem yəhûḏāh lāgûr baʾăšer yimṣāʾ wayyāḇōʾ har-ʾeprayim ʿaḏ-bêt mîkāh laʿăśôt darkô</em> — 'The man departed from the city of Bethlehem in Judah to sojourn wherever he could find a place. As he traveled, he came to the hill country of Ephraim to the house of Micah.' <em>lāgûr baʾăšer yimṣāʾ</em> — 'to sojourn wherever he could find' — the Levite is economically migrating: searching for a place of residence and provision. The Levitical system required Israel to support the Levites (Deut 14:29; 18:1-8), but in the period of 'no king in Israel,' that system has broken down. The Levite arrives at Micah's house by apparently random travel (<em>darkô</em>, 'his road/way') — but the narrative will show YHWH's judgment working through this encounter.</p>",
    "9": "<p><em>wayyōʾmer lô mîkāh mēʾayin tāḇôʾ wayyōʾmer ʾēlāyw lēwî ʾānôkî mibbêt leḥem yəhûḏāh wəʾānōkî hōlēk lāgûr baʾăšer ʾimṣāʾ</em> — 'Micah said to him: Where do you come from? He said to him: I am a Levite from Bethlehem in Judah, and I am going to sojourn wherever I may find a place.' The Levite's self-identification as a Levite (<em>lēwî ʾānôkî</em>) immediately interests Micah: he needs a legitimate priest for his shrine, and a genuine Levite is better than his son (v5). The exchange is transactional from the start: Micah asks 'where from?' — a standard hospitality question — and the Levite's answer triggers Micah's opportunistic offer in v10.</p>",
    "10": "<p><em>wayyōʾmer lô mîkāh šəḇāh ʿimmādî wahyēh lî ləʾāḇ ûləkōhēn wəʾānōkî ʾettēn-ləkā ʿăśeret kəsep layyāmîm ûʿerek bəḡāḏîm ûmiḥyātekā</em> — 'Micah said to him: Stay with me, and be to me a father and a priest, and I will give you ten pieces of silver a year and a suit of clothes and your food.' <em>ləʾāḇ ûləkōhēn</em> (to be a father and a priest) — 'father' here is a term of honor and authority: a spiritual advisor and authority figure in the household. The employment contract is explicit: ten silver pieces annually, one set of clothing, and food — a standard service arrangement. The Levite is hired as a domestic chaplain for an idolatrous shrine: his priestly legitimacy is being rented to cover an illegitimate religious enterprise.</p>",
    "11": "<p><em>wayyôʾel halēwî lāšeḇet ʾet-hāʾîš wayhî hannáʿar lô kəʾaḥaḏ mibbānāyw</em> — 'And the Levite agreed to stay with the man, and the young man was to him like one of his sons.' <em>wayyôʾel</em> (H2974, to be willing/consent/agree) — the Levite consents to the arrangement. <em>kəʾaḥaḏ mibbānāyw</em> (like one of his sons) — Micah adopts the young Levite into quasi-filial status: the previous family-priest son (v5) is replaced by a professional. The family relationship language masks a contractual arrangement: the Levite is an employee, not a family member, despite the domestic metaphor. This pseudo-adoption language will collapse when a better offer comes (ch18).</p>",
    "12": "<p><em>wayyəmallēʾ mîkāh ʾet-yaḏ halēwî wayhî-lô hannáʿar ləkōhēn wayhî bəbêt mîkāh</em> — 'And Micah filled the hand of the Levite, and the young man became his priest, and was in the house of Micah.' <em>millēʾ yāḏ</em> (to fill the hand — the ordination formula, Exod 28:41; 29:9; Lev 8:33) — Micah formally installs the Levite using proper ordination language for an entirely improper purpose. The ordination formula belongs to the tabernacle consecration of Aaron and his sons under divine command; Micah applies it to a private shrine with hired personnel. The gap between correct ritual language and corrupt religious practice is the chapter's defining irony.</p>",
    "13": "<p><em>wayyōʾmer mîkāh ʿattāh yāḏaʿtî kî-yêṭîḇ YHWH lî kî hāyāh lî haLēwî ləkōhēn</em> — 'Micah said: Now I know that YHWH will do me good, because I have a Levite as priest.' Micah's theological logic is entirely superstitious: having the right ritual personnel guarantees divine blessing, regardless of what those personnel are doing. <em>yêṭîḇ YHWH lî</em> (YHWH will do good for me) — a prosperity assumption disconnected from covenant obedience. The Levite being hired as a private priest is itself a violation (Levites were to serve at the tabernacle, not in private shrines). Yet Micah is satisfied because he now has a 'real' priest for his idolatrous shrine — the tragedy of religious formalism that substitutes correct procedure for correct worship.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'judges')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', 'judges', c)
    print(f'judges mkt-original: wrote {sum(len(v) for v in ORIGINAL.values())} verses across ch 14-17')

if __name__ == '__main__':
    main()
